// Turndown.js 简化版本 - HTML to Markdown 转换器
(function (global, factory) {
    if (typeof exports === 'object' && typeof module !== 'undefined') {
        module.exports = factory();
    } else if (typeof define === 'function' && define.amd) {
        define(factory);
    } else {
        global.TurndownService = factory();
    }
}(this, function () {
    'use strict';

    function TurndownService(options) {
        this.options = Object.assign({
            headingStyle: 'setext',
            hr: '* * *',
            bulletListMarker: '*',
            codeBlockStyle: 'indented',
            fence: '```',
            emDelimiter: '_',
            strongDelimiter: '**',
            linkStyle: 'inlined',
            linkReferenceStyle: 'full'
        }, options);

        this.rules = {
            paragraph: {
                filter: 'p',
                replacement: function (content) {
                    return '\n\n' + content + '\n\n';
                }
            },
            
            lineBreak: {
                filter: 'br',
                replacement: function () {
                    return '  \n';
                }
            },

            heading: {
                filter: ['h1', 'h2', 'h3', 'h4', 'h5', 'h6'],
                replacement: function (content, node, options) {
                    var hLevel = parseInt(node.nodeName.charAt(1), 10);
                    if (options.headingStyle === 'setext' && hLevel < 3) {
                        var underline = hLevel === 1 ? '=' : '-';
                        return '\n\n' + content + '\n' + new Array(content.length + 1).join(underline) + '\n\n';
                    } else {
                        return '\n\n' + new Array(hLevel + 1).join('#') + ' ' + content + '\n\n';
                    }
                }
            },

            blockquote: {
                filter: 'blockquote',
                replacement: function (content) {
                    content = content.replace(/^\n+|\n+$/g, '');
                    content = content.replace(/^/gm, '> ');
                    return '\n\n' + content + '\n\n';
                }
            },

            list: {
                filter: ['ul', 'ol'],
                replacement: function (content, node) {
                    var parent = node.parentNode;
                    if (parent.nodeName === 'LI' && parent.lastElementChild === node) {
                        return '\n' + content;
                    } else {
                        return '\n\n' + content + '\n\n';
                    }
                }
            },

            listItem: {
                filter: 'li',
                replacement: function (content, node, options) {
                    content = content.replace(/^\n+/, '').replace(/\n+$/, '\n').replace(/\n/gm, '\n    ');
                    var prefix = options.bulletListMarker + '   ';
                    var parent = node.parentNode;
                    if (parent.nodeName === 'OL') {
                        var start = parent.getAttribute('start');
                        var index = Array.prototype.indexOf.call(parent.children, node);
                        prefix = (start ? Number(start) + index : index + 1) + '.  ';
                    }
                    return prefix + content + (node.nextSibling && !/\n$/.test(content) ? '\n' : '');
                }
            },

            emphasis: {
                filter: ['em', 'i'],
                replacement: function (content, node, options) {
                    if (!content.trim()) return '';
                    return options.emDelimiter + content + options.emDelimiter;
                }
            },

            strong: {
                filter: ['strong', 'b'],
                replacement: function (content, node, options) {
                    if (!content.trim()) return '';
                    return options.strongDelimiter + content + options.strongDelimiter;
                }
            },

            code: {
                filter: function (node) {
                    var hasSiblings = node.previousSibling || node.nextSibling;
                    var isCodeBlock = node.parentNode.nodeName === 'PRE' && !hasSiblings;
                    return node.nodeName === 'CODE' && !isCodeBlock;
                },
                replacement: function (content) {
                    if (!content.trim()) return '';
                    var delimiter = '`';
                    if (content.indexOf('`') !== -1) {
                        delimiter = '``';
                    }
                    return delimiter + content + delimiter;
                }
            },

            image: {
                filter: 'img',
                replacement: function (content, node) {
                    var alt = node.alt || '';
                    var src = node.src || '';
                    var title = node.title || '';
                    var titlePart = title ? ' "' + title + '"' : '';
                    return src ? '![' + alt + '](' + src + titlePart + ')' : '';
                }
            },

            link: {
                filter: function (node, options) {
                    return options.linkStyle === 'inlined' && node.nodeName === 'A' && node.getAttribute('href');
                },
                replacement: function (content, node) {
                    var href = node.getAttribute('href');
                    var title = node.title ? ' "' + node.title + '"' : '';
                    return '[' + content + '](' + href + title + ')';
                }
            },

            horizontalRule: {
                filter: 'hr',
                replacement: function (content, node, options) {
                    return '\n\n' + options.hr + '\n\n';
                }
            }
        };
    }

    TurndownService.prototype.turndown = function (input) {
        if (typeof input === 'string') {
            var div = document.createElement('div');
            div.innerHTML = input;
            input = div;
        }
        return this.convert(input);
    };

    TurndownService.prototype.convert = function (node) {
        var self = this;
        
        if (node.nodeType === 3) { // Text node
            return node.textContent;
        } else if (node.nodeType === 1) { // Element node
            var tagName = node.nodeName.toLowerCase();
            
            // Find matching rule
            var rule = null;
            for (var ruleName in this.rules) {
                var r = this.rules[ruleName];
                if (this.filterValue(r.filter, node)) {
                    rule = r;
                    break;
                }
            }
            
            var content = '';
            for (var i = 0; i < node.childNodes.length; i++) {
                content += this.convert(node.childNodes[i]);
            }
            
            if (rule && rule.replacement) {
                return rule.replacement(content, node, this.options);
            } else {
                return content;
            }
        }
        
        return '';
    };

    TurndownService.prototype.filterValue = function (filter, node) {
        if (typeof filter === 'string') {
            return filter === node.nodeName.toLowerCase();
        } else if (Array.isArray(filter)) {
            return filter.indexOf(node.nodeName.toLowerCase()) !== -1;
        } else if (typeof filter === 'function') {
            return filter.call(this, node, this.options);
        } else {
            return false;
        }
    };

    TurndownService.prototype.addRule = function (key, rule) {
        this.rules[key] = rule;
        return this;
    };

    TurndownService.prototype.keep = function (filter) {
        this.addRule('keep', {
            filter: filter,
            replacement: function (content, node) {
                return node.outerHTML;
            }
        });
        return this;
    };

    TurndownService.prototype.remove = function (filter) {
        this.addRule('remove', {
            filter: filter,
            replacement: function () {
                return '';
            }
        });
        return this;
    };

    return TurndownService;
}));
